import PriorityQueue from 'priorityqueuejs';

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const dirs = [[0, 1], [1, 0]]; // right and down directions
    const dist = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => 
            Array(k + 1).fill(Infinity)
        )
    );
    dist[0][0][0] = 0;

    const pq = new PriorityQueue((a, b) => b[0] - a[0]);
    pq.enq([0, 0, 0, 0]); // [cost, i, j, usedK]

    while (!pq.isEmpty()) {
        const [cost, i, j, usedK] = pq.deq();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][usedK]) {
            continue;
        }

        // Normal moves
        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni < m && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][usedK]) {
                    dist[ni][nj][usedK] = newCost;
                    pq.enq([newCost, ni, nj, usedK]);
                }
            }
        }

        // Teleport moves
        if (usedK < k) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j] && (x !== i || y !== j)) {
                        if (cost < dist[x][y][usedK + 1]) {
                            dist[x][y][usedK + 1] = cost;
                            pq.enq([cost, x, y, usedK + 1]);
                        }
                    }
                }
            }
        }
    }

    return Math.min(...dist[m - 1][n - 1]);
}
